import { useEvent } from "../hooks/use-event.js";
export function useRowChildren(tree) {
    const rowChildren = useEvent((id) => {
        const group = tree?.groupLookup.get(id);
        if (!group)
            return [];
        const ids = [...group.children.values()].map((x) => x.row.id);
        return ids;
    });
    return rowChildren;
}
